queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?housekeeping a :Housekeeping .
    ?housekeeping p:housekeeper ?housekeeper .
    BIND(?housekeeper AS ?o0)
  }
  UNION
  {
    ?laundryservice a :LaundryService .
    ?laundryservice p:laundry_attendant ?laundry_attendant .
    ?laundryservice p:hotel ?hotel_f .
    FILTER(STR(?hotel_f) = "The Grand Hotel")
    BIND(?laundry_attendant AS ?o0)
  }
}

